import json
import os
import pymysql

def lambda_handler(event, context):
    db_host = os.environ.get('DB_HOST')
    db_user = os.environ.get('DB_USER')
    db_password = os.environ.get('DB_PASSWORD')
    db_name = os.environ.get('DB_NAME')
    db_port = int(os.environ.get('DB_PORT', 3306))

    if not all([db_host, db_user, db_password, db_name]):
        return {
            'statusCode': 500,
            'body': json.dumps('Database connection environment variables are not set.')
        }

    try:
        connection = pymysql.connect(
            host=db_host,
            user=db_user,
            password=db_password,
            database=db_name,
            port=db_port,
            cursorclass=pymysql.cursors.DictCursor
        )
    except pymysql.Error as e:
        print(f"ERROR: Could not connect to MySQL instance: {e}")
        return {
            'statusCode': 500,
            'body': json.dumps(f"Failed to connect to database: {e}")
        }

    search_params = {}
    if event.get('queryStringParameters'):
        search_params = event['queryStringParameters']
    elif event.get('body'):
        try:
            search_params = json.loads(event['body'])
        except json.JSONDecodeError:
            return {
                'statusCode': 400,
                'body': json.dumps('Invalid JSON in request body.')
            }

    query = "SELECT product_id, name, description, price, category, stock_quantity FROM products"
    where_clauses = []
    query_params = []

    if 'name' in search_params and search_params['name']:
        where_clauses.append("name LIKE %s")
        query_params.append(f"%{search_params['name']}%")

    if 'category' in search_params and search_params['category']:
        where_clauses.append("category = %s")
        query_params.append(search_params['category'])

    if 'min_price' in search_params and search_params['min_price']:
        try:
            min_price = float(search_params['min_price'])
            where_clauses.append("price >= %s")
            query_params.append(min_price)
        except ValueError:
            pass # Ignore invalid price values

    if 'max_price' in search_params and search_params['max_price']:
        try:
            max_price = float(search_params['max_price'])
            where_clauses.append("price <= %s")
            query_params.append(max_price)
        except ValueError:
            pass # Ignore invalid price values

    if 'in_stock' in search_params:
        in_stock = str(search_params['in_stock']).lower()
        if in_stock == 'true' or in_stock == '1':
            where_clauses.append("stock_quantity > 0")
        elif in_stock == 'false' or in_stock == '0':
            where_clauses.append("stock_quantity = 0")
            
    if 'product_id' in search_params and search_params['product_id']:
        where_clauses.append("product_id = %s")
        query_params.append(search_params['product_id'])

    if where_clauses:
        query += " WHERE " + " AND ".join(where_clauses)

    products = []
    try:
        with connection.cursor() as cursor:
            print(f"Executing query: {query} with params: {query_params}")
            cursor.execute(query, tuple(query_params))
            products = cursor.fetchall()
    except pymysql.Error as e:
        print(f"ERROR: Could not execute query: {e}")
        return {
            'statusCode': 500,
            'body': json.dumps(f"Failed to query database: {e}")
        }
    finally:
        connection.close()

    return {
        'statusCode': 200,
        'headers': {
            'Content-Type': 'application/json'
        },
        'body': json.dumps(products)
    }